from instructor import from_openai
from pydantic import BaseModel, Field
from vex import verify

class StudentProfile(BaseModel):
    student_id: str
    consent_status: str = Field(..., regex='^(verified|pending|denied)$')
    grade_level: str = Field(..., regex='^(K-5|6-8|9-12)$')
    assessment_score: float | None = None

client = from_openai(openai_client)
@verify(guards=["pii_redact", "ferpa_compliance"])
def extract_student_profile(prompt: str) -> StudentProfile:
    return client.messages.create(
        model="gpt-4o",
        response_model=StudentProfile,
        messages=[{"role": "user", "content": prompt}]
    )

import { fromOpenai } from '@instructor-ai/instructor';
import { z } from 'zod';
import { verify } from 'vex-sdk';

const StudentSessionSchema = z.object({
  sessionId: z.string(),
  studentId: z.string().min(1),
  parentalConsent: z.enum(['verified', 'pending', 'denied']),
  contentLevel: z.enum(['K-5', '6-8', '9-12']),
  accessibilityTags: z.array(z.string()).min(2),
});

type StudentSession = z.infer<typeof StudentSessionSchema>;

const client = fromOpenai(openai);

export const logStudentSession = verify(
  (prompt: string) => client.chat.completions.create({
    model: 'gpt-4o',
    responseModel: StudentSessionSchema,
    messages: [{ role: 'user', content: prompt }],
  }),
  { guards: ['ferpa', 'coppa'] }
);
